INSERT INTO catalog_items (id, item_type, name, description, category_id, lat, lng, estimated_duration_minutes, approx_cost_clp, is_active, extra) VALUES (1, 'place', 'Parque Nacional Queulat', 'Parque nacional con ventisquero colgante; accesos desde La Junta, Puyuhuapi y Puerto Cisnes.', 1, NULL, NULL, NULL, NULL, True, '{"tags": "parque nacional, glaciar, senderismo", "ubicacion": "Carretera Austral Norte", "acceso_como_llegar": "Desde La Junta: 65 km al sur (~1 h). Desde Puyuhuapi: 20 km al sur (~20 min). Desde Puerto Cisnes: 64 km al norte (~1 h)."}');
INSERT INTO catalog_items (id, item_type, name, description, category_id, lat, lng, estimated_duration_minutes, approx_cost_clp, is_active, extra) VALUES (2, 'place', 'Parque Nacional Patagonia', 'Parque nacional con sectores Jeinimeni, Valle Chacabuco y Tamango; trekking y observación de fauna.', 1, NULL, NULL, NULL, NULL, True, '{"tags": "parque nacional, senderismo, bicicleta, huemul", "ubicacion": "Chile Chico / Cochrane", "acceso_como_llegar": "Sector Jeinimeni: 65 km al sur de Chile Chico. Valle Chacabuco: 28 km al norte de Cochrane. Tamango: 4 km NE de Cochrane."}');
INSERT INTO catalog_items (id, item_type, name, description, category_id, lat, lng, estimated_duration_minutes, approx_cost_clp, is_active, extra) VALUES (3, 'place', 'Reserva Nacional Coyhaique', 'Reserva cercana a Coyhaique con horarios de ingreso y senderos.', 1, NULL, NULL, NULL, NULL, True, '{"tags": "reserva nacional, senderismo", "ubicacion": "Coyhaique", "acceso_como_llegar": "A 5 km norte de Coyhaique (salida hacia Carretera Austral)."}');
INSERT INTO catalog_items (id, item_type, name, description, category_id, lat, lng, estimated_duration_minutes, approx_cost_clp, is_active, extra) VALUES (4, 'place', 'Reserva Nacional Río Simpson', 'Reserva en Ruta 240 entre Coyhaique y Puerto Aysén; sendero inclusivo y sendero Los Pioneros (3 km).', 1, NULL, NULL, NULL, NULL, True, '{"tags": "reserva nacional, sendero inclusivo, aves", "ubicacion": "Ruta 240 (Coyhaique–Puerto Aysén)", "recomendaciones": "Camping cerrado; reservas/entradas en pasesparques.cl.", "acceso_como_llegar": "Desde Coyhaique: 25 km por Ruta 240. Desde Puerto Aysén: 35 km por Ruta 240."}');
INSERT INTO catalog_items (id, item_type, name, description, category_id, lat, lng, estimated_duration_minutes, approx_cost_clp, is_active, extra) VALUES (5, 'place', 'Monumento Natural Dos Lagunas', 'Área protegida cercana a Coyhaique; se recomienda comprar pase con anticipación y llevarlo impreso por baja conectividad.', 1, NULL, NULL, NULL, NULL, True, '{"tags": "monumento natural, conaf, pasesparques", "ubicacion": "Cercano a Coyhaique", "recomendaciones": "Comprar pase anticipado en pasesparques.cl y llevarlo impreso."}');
INSERT INTO catalog_items (id, item_type, name, description, category_id, lat, lng, estimated_duration_minutes, approx_cost_clp, is_active, extra) VALUES (6, 'place', 'Confluencia Ríos Baker y Nef', 'Mirador de confluencia con opciones de rafting, flotadas y pesca (en otros sectores).', 1, NULL, NULL, NULL, NULL, True, '{"tags": "río baker, río nef, rafting, fotografía", "ubicacion": "Puerto Bertrand / Puerto Guadal / Cochrane", "acceso_como_llegar": "Desde Puerto Bertrand: 12,5 km por Carretera Austral sur. Desde Cochrane: 37 km salida norte. Desde Puerto Guadal: Ruta 265 + Carretera Austral sur."}');
INSERT INTO catalog_items (id, item_type, name, description, category_id, lat, lng, estimated_duration_minutes, approx_cost_clp, is_active, extra) VALUES (7, 'place', 'Lago General Carrera', 'Lago más grande de Chile; actividades outdoor como pesca deportiva, cabalgatas, navegación y trekking.', 1, NULL, NULL, NULL, NULL, True, '{"tags": "lago, navegación, pesca, trekking", "ubicacion": "Provincia General Carrera", "acceso_como_llegar": "195 km al sur de Coyhaique por la Carretera Austral."}');
INSERT INTO catalog_items (id, item_type, name, description, category_id, lat, lng, estimated_duration_minutes, approx_cost_clp, is_active, extra) VALUES (8, 'place', 'Glaciar Calluqueo', 'Glaciar cerca de Cochrane con mirador y opciones de trekking o caminata sobre hielo con guía.', 1, NULL, NULL, NULL, NULL, True, '{"tags": "glaciar, trekking, hielo", "ubicacion": "Cercano a Cochrane (Monte San Lorenzo)", "recomendaciones": "Planificar con anticipación.", "acceso_como_llegar": "Desde Cochrane: Ruta X-901 sur; desvío X-903 tras puente sobre Río Tranquilo; hasta mirador."}');
INSERT INTO catalog_items (id, item_type, name, description, category_id, lat, lng, estimated_duration_minutes, approx_cost_clp, is_active, extra) VALUES (9, 'place', 'Campos de Hielo (Norte y Sur)', 'Accesos a Campo de Hielo Norte/Sur y actividades como ice-trekking, navegación y trekking a glaciares.', 1, NULL, NULL, NULL, NULL, True, '{"tags": "campo de hielo, glaciares, navegación", "ubicacion": "Aysén (múltiples accesos)", "acceso_como_llegar": "CHN: Pto Chacabuco→Laguna San Rafael; Pto Río Tranquilo→valle Exploradores; Pto Guadal→Glaciar Leones; Tortel→Glaciar Steffen. CHS: Villa O''Higgins→lago O''Higgins; Tortel→Jorge Montt/Bernardo O''Higgins."}');
INSERT INTO catalog_items (id, item_type, name, description, category_id, lat, lng, estimated_duration_minutes, approx_cost_clp, is_active, extra) VALUES (10, 'place', 'Reserva Nacional Las Guaitecas', 'Reserva con acceso únicamente marítimo; turismo aventura, pesca artesanal, buceo y tránsito de embarcaciones.', 1, NULL, NULL, NULL, NULL, True, '{"tags": "reserva nacional, buceo, pesca artesanal", "ubicacion": "Archipiélago de las Guaitecas", "acceso_como_llegar": "Acceso únicamente marítimo."}');
INSERT INTO catalog_items (id, item_type, name, description, category_id, lat, lng, estimated_duration_minutes, approx_cost_clp, is_active, extra) VALUES (11, 'place', 'Reserva Nacional Lago Las Torres', 'Reserva en km 120 de Carretera Austral norte; permanencia limitada por riesgo de derrumbes.', 1, NULL, NULL, NULL, NULL, True, '{"tags": "reserva nacional, seguridad", "ubicacion": "Ruta 7 km 120", "recomendaciones": "No permanecer más de un tiempo prudente por riesgo de derrumbes."}');
INSERT INTO catalog_items (id, item_type, name, description, category_id, lat, lng, estimated_duration_minutes, approx_cost_clp, is_active, extra) VALUES (12, 'place', 'Reserva Nacional Lago Carlota', 'Reserva accesible por ruta X-25 desde bifurcación de Ruta 7 en Villa Amengual; excursión y senderismo.', 1, NULL, NULL, NULL, NULL, True, '{"tags": "reserva nacional, senderismo", "ubicacion": "Villa Amengual / Villa Tapera", "acceso_como_llegar": "Ruta X-25 (bifurcación Ruta 7 en Villa Amengual) hacia Villa Tapera."}');
